try {
  const item = $('Loop: Processar 1 a 2').first().json;
  const history = $input.item.json;
  let events = [];
  if (history?.data?.shipping_history?.events) {
    events = history.data.shipping_history.events;
  } else if (Array.isArray(history)) {
    const data = history[0];
    if (data?.data?.shipping_history?.events) {
      events = data.data.shipping_history.events;
    }
  }
  const has1600 = events.some(e => e.code === '1600' || e.event_code === '1600');
  let formattedHistory = 'Sin eventos disponibles';
  if (events.length > 0) {
    formattedHistory = events.map(e => {
      let date = e.event_date || e.item_event_date || '';
      if (date) {
        try {
          const d = new Date(date);
          d.setHours(d.getHours() + 1);
          date = d.toISOString().replace('T', ' ').substring(0, 16);
        } catch(x) {}
      }
      const code = e.code || e.event_code || 'N/A';
      const desc = e.description || e.event_description || '';
      const detail = e.detail?.External_event_text || e.detail?.item_event_text || '';
      return `${date} - [${code}] ${desc} (${detail})`;
    }).join('\n');
  }
  return {
    json: {
      ...item,
      status_history: events,
      formatted_history: formattedHistory,
      history_has_1600: has1600,
      total_events: events.length
    }
  };
} catch (error) {
  throw new Error(`[Code JS3] ${error.message}`);
}

const rows = $input.all();
const item = $('Code in JavaScript3').item.json;
const hoy = $now.toFormat('dd-MM-yyyy');
const ayer = $now.minus({days: 1}).toFormat('dd-MM-yyyy');

const filasValidas = rows.filter(r => r.json['NUMERO DE ENVIO']);

const filasHoy = filasValidas.filter(r => {
  const fecha = (r.json['FECHA PROCESADO'] || '').substring(0, 10);
  return fecha === hoy;
});

const filasAyer = filasValidas.filter(r => {
  const fecha = (r.json['FECHA PROCESADO'] || '').substring(0, 10);
  return fecha === ayer;
});

const is2500 = String(item.shipping_status_code || '') === '2500';

const skip = filasHoy.length > 0;
const forceInternal = !skip && (filasAyer.length > 0 || is2500);
const numeroAvisos = filasValidas.length + 1;

return {
  json: {
    ...item,
    skip,
    force_internal: forceInternal,
    is_2500: is2500,
    numero_avisos: numeroAvisos
  }
};

